// Deterministic daily market data: a fluctuation % and the quarter it fell in.
function marketData() {
  var quarters = ['Q1', 'Q2', 'Q3', 'Q4']
  var out = []
  for (var i = 0; i < 92; i++) {
    var pct =
      3.2 * Math.sin(i / 4.0) +
      1.4 * Math.sin(i / 1.3) +
      0.5 * Math.cos(i / 2.7)
    out.push({
      day: i,
      pct: Math.round(pct * 100) / 100,
      q: quarters[Math.floor(i / 23) % 4],
    })
  }
  return out
}

// Register the shared records BEFORE the charts are constructed.
ApexCharts.crossfilter({ id: 'market', records: marketData() })

var options = {
  series: [],
  chart: {
    id: 'fluctuation',
    type: 'bar',
    height: 260,
    fontFamily: 'Helvetica, Arial, sans-serif',
    animations: { speed: 450 },
    zoom: { enabled: false },
    selection: { enabled: true },
    toolbar: {
      autoSelected: 'selection',
      tools: {
        selection: true,
        zoom: false,
        pan: false,
        reset: false,
        download: false,
      },
    },
    link: {
      id: 'market',
      dimension: function (r) {
        return r.pct
      },
      bins: { count: 24 },
      dimOpacity: 0.16,
    },
  },
  title: { text: 'Daily fluctuation % (brush a range here)', align: 'left' },
  plotOptions: { bar: { columnWidth: '92%' } },
  dataLabels: { enabled: false },
  xaxis: {
    type: 'numeric',
    tickAmount: 8,
    labels: {
      formatter: function (v) {
        return Number(v).toFixed(1) + '%'
      },
    },
  },
  colors: ['#6366f1'],
}

var chart = new ApexCharts(document.querySelector('#chart'), options)
chart.render()

var options1 = {
  series: [],
  chart: {
    id: 'byQuarter',
    type: 'bar',
    height: 240,
    fontFamily: 'Helvetica, Arial, sans-serif',
    animations: { speed: 450 },
    link: {
      id: 'market',
      dimension: function (r) {
        return r.q
      },
      reduce: 'count',
      seriesName: 'Days',
    },
  },
  title: { text: 'Days by quarter (crossfiltered)', align: 'left' },
  plotOptions: {
    bar: { columnWidth: '55%', borderRadius: 3, distributed: true },
  },
  legend: { show: false },
  dataLabels: { enabled: true },
  colors: ['#6366f1', '#0ea5e9', '#22c55e', '#f59e0b'],
}

var chart1 = new ApexCharts(document.querySelector('#chart2'), options1)
chart1.render()

// charts[0] = fluctuation histogram (brush source), charts[1] = byQuarter.
// The wiring talks to the crossfilter engine (not the chart instances).
var cf = ApexCharts.getCrossfilter('market')
var readout = document.getElementById('cf-readout')

if (cf) {
  cf.on('change', function (state) {
    var r = state.filters.fluctuation
    if (r) {
      readout.textContent =
        'Fluctuation ' +
        r[0].toFixed(2) +
        '% to ' +
        r[1].toFixed(2) +
        '%   ->   ' +
        state.filteredCount +
        ' / ' +
        state.total +
        ' days'
    } else {
      readout.textContent = 'No filter (all ' + state.total + ' days)'
    }
  })
}

document.getElementById('cf-reset').addEventListener('click', function () {
  if (cf) cf.reset()
})

.cf-wrap {
  max-width: 700px;
  margin: 12px auto;
  font-family: Helvetica, Arial, sans-serif;
}
.cf-bar {
  display: flex;
  gap: 12px;
  align-items: center;
  flex-wrap: wrap;
  margin: 4px 6px 12px;
}
.cf-bar button {
  padding: 6px 13px;
  cursor: pointer;
  border: 1px solid #6366f1;
  color: #4338ca;
  background: #fff;
  border-radius: 6px;
  font-size: 13px;
  font-weight: 600;
}
.cf-bar .readout {
  font-family: monospace;
  font-size: 13px;
  color: #445;
}
.cf-card {
  border: 1px solid #eef;
  border-radius: 8px;
  padding: 6px;
  margin-bottom: 8px;
}
.cf-note {
  background: #eef2ff;
  border-left: 3px solid #6366f1;
  padding: 11px 15px;
  font-size: 13px;
  color: #234;
  border-radius: 2px;
  line-height: 1.6;
  margin: 12px 6px;
}
.cf-note code {
  background: #dfe3ff;
  padding: 1px 5px;
  border-radius: 3px;
}
